fn common_prefix_len(a: &str, b: &str) -> i64 {
    let a_bytes = a.as_bytes();
    let b_bytes = b.as_bytes();
    let min_len = a_bytes.len().min(b_bytes.len());
    let mut i = 0;
    while i < min_len && a_bytes[i] == b_bytes[i] {
        i += 1;
    }
    i as i64
}

fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    if n == 1 {
        return vec![0];
    }

    let mut orig_pair_lcp = vec![0; n-1];
    for i in 0..n-1 {
        orig_pair_lcp[i] = common_prefix_len(&words[i], &words[i+1]);
    }

    let mut prefix_max = vec![0; n-1];
    prefix_max[0] = orig_pair_lcp[0];
    for i in 1..n-1 {
        prefix_max[i] = prefix_max[i-1].max(orig_pair_lcp[i]);
    }

    let mut suffix_max = vec![0; n-1];
    let last_index = n - 2;
    suffix_max[last_index] = orig_pair_lcp[last_index];
    if last_index > 0 {
        for i in (0..last_index).rev() {
            suffix_max[i] = suffix_max[i+1].max(orig_pair_lcp[i]);
        }
    }

    let mut answer = vec![0; n];
    for i in 0..n {
        let max_left = if i <= 1 { 
            0 
        } else { 
            prefix_max[i-2] 
        };

        let max_right = if i >= n - 2 { 
            0 
        } else { 
            suffix_max[i+1] 
        };

        let mid = if i >= 1 && i < n - 1 {
            common_prefix_len(&words[i-1], &words[i+1])
        } else {
            0
        };

        answer[i] = max_left.max(max_right).max(mid);
    }

    answer
}
