    let n = words.len();
    let mut answer = vec![0; n];

    if n == 1 {
        return answer;
    }

    // Precompute the LCP between adjacent words in the original array
    let mut original_lcps = vec![0; n - 1];
    for i in 0..n - 1 {
        original_lcps[i] = common_prefix(&words[i], &words[i + 1]);
    }

    for i in 0..n {
        let mut max_lcp = 0;

        if n == 2 {
            // Only one pair left, which is either (0,1) or (1,0) depending on removal
            // But since we remove one, there's no adjacent pair left
            answer[i] = 0;
            continue;
        }

        // Check the adjacent pairs that are affected by removing i
        if i > 0 && i < n - 1 {
            // The new adjacent pair is (i-1, i+1)
            let new_lcp = common_prefix(&words[i - 1], &words[i + 1]);
            max_lcp = new_lcp;
        }

        // Check the original adjacent pairs not involving i
        // Pairs before i-1
        if i > 0 {
            for j in 0..i - 1 {
                if original_lcps[j] > max_lcp {
                    max_lcp = original_lcps[j];
                }
            }
        }
        // Pairs after i+1
        if i < n - 1 {
            for j in i + 1..n - 1 {
                if original_lcps[j] > max_lcp {
                    max_lcp = original_lcps[j];
                }
            }
        }

        answer[i] = max_lcp as i64;
    }

    answer
}

